using UnityEngine;
using System.Collections.Generic;

// Game Manager — central controller for game state
public class GameManager : MonoBehaviour
{
    // Singleton pattern
    public static GameManager Instance { get; private set; }

    // Game state
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver
    }

    public GameState CurrentState { get; private set; } = GameState.Menu;

    // Player data
    public int PlayerScore { get; private set; }
    public int PlayerLives { get; private set; }
    public int CurrentLevel { get; private set; } = 1;

    // Events
    public System.Action<GameState> OnStateChanged;
    public System.Action<int> OnScoreChanged;
    public System.Action<int> OnLivesChanged;
    public System.Action<int> OnLevelChanged;

    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
            InitializeGame();
        }
        else
        {
            Destroy(gameObject);
        }
    }

    void InitializeGame()
    {
        PlayerScore = 0;
        PlayerLives = 3;
        CurrentLevel = 1;

        Debug.Log("Game initialized!");
    }

    public void StartGame()
    {
        SetState(GameState.Playing);
        Debug.Log("Game started!");
    }

    public void PauseGame()
    {
        if (CurrentState == GameState.Playing)
        {
            SetState(GameState.Paused);
            Time.timeScale = 0f;
            Debug.Log("Game paused!");
        }
        else if (CurrentState == GameState.Paused)
        {
            SetState(GameState.Playing);
            Time.timeScale = 1f;
            Debug.Log("Game resumed!");
        }
    }

    public void GameOver()
    {
        SetState(GameState.GameOver);
        Time.timeScale = 0f;
        Debug.Log("Game Over! Final Score: " + PlayerScore);
    }

    public void AddScore(int points)
    {
        PlayerScore += points;
        OnScoreChanged?.Invoke(PlayerScore);
        Debug.Log("Score: " + PlayerScore);

        // Check for achievements
        if (PlayerScore >= 100)
        {
            Debug.Log("Achievement unlocked: 100 points!");
        }
    }

    public void LoseLife()
    {
        PlayerLives--;
        OnLivesChanged?.Invoke(PlayerLives);
        Debug.Log("Lives: " + PlayerLives);

        if (PlayerLives <= 0)
        {
            GameOver();
        }
    }

    public void NextLevel()
    {
        CurrentLevel++;
        OnLevelChanged?.Invoke(CurrentLevel);
        Debug.Log("Level: " + CurrentLevel);

        // Reset player position, enemies, etc.
    }

    void SetState(GameState newState)
    {
        if (CurrentState != newState)
        {
            CurrentState = newState;
            OnStateChanged?.Invoke(CurrentState);
        }
    }
}

// Example of using GameManager
public class GameManagerUsage : MonoBehaviour
{
    void Start()
    {
        // Subscribe to events
        GameManager.Instance.OnStateChanged += OnGameStateChanged;
        GameManager.Instance.OnScoreChanged += OnScoreChanged;

        // Start the game
        GameManager.Instance.StartGame();

        // Add some score
        GameManager.Instance.AddScore(25);
        GameManager.Instance.AddScore(50);

        // Simulate losing a life
        GameManager.Instance.LoseLife();

        // Next level
        GameManager.Instance.NextLevel();
    }

    void OnGameStateChanged(GameManager.GameState state)
    {
        Debug.Log("State changed to: " + state);
    }

    void OnScoreChanged(int score)
    {
        Debug.Log("Score updated: " + score);

        // Update UI
